import numpy as np

def U_power_2k(U, k):
    result = U.copy()
    for _ in range(k):
        result = result @ result
    return result

def Rz(theta):
    return np.array([[np.exp(-1j*theta/2), 0], [0, np.exp(1j*theta/2)]])

R = Rz(np.pi/16)
print("Rz(π/16) powers via repeated squaring:")
for k in range(5):
    Rk = U_power_2k(R, k)
    phase = np.angle(Rk[1,1]) * 2
    expected = (np.pi/16) * (2**k)
    print(f"  k={k}: Rz^{2**k} phase = {phase/np.pi:.4f}π (expected {expected/np.pi:.4f}π)")
